var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"한 가지 묻고 싶은 게 있어, 파벨라.","JPN":"1つ聞きたいことがある、ファヴェーラ。","ENG":"There’s one thing I want to ask you, Fabella.","TWN":"帕貝拉，我有件事想問你。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"동료 다니엘이 나에게 말해줬어.","JPN":"同僚のダニエルが俺に言ったんだ。","ENG":"Daniel told me...","TWN":"丹尼爾跟我說，"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신이 프레데리카와 같은 오퍼레이터 동기이자 아주 친한 친구였다고 말이야.","JPN":"君とフレデリカはオペレーターの同期であり、とても仲のいい友人だったと。","ENG":"That you and Frederica were both operator colleagues and best friends.","TWN":"你和弗蕾德莉卡是同梯，而且還是很好的朋友。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"어째서 사령부 권한까지 동원해가며, 프레데리카를 전쟁터로 내몰았던 거지?","JPN":"なぜ司令部の権限を行使してまで、フレデリカを戦場に追いやったんだ？","ENG":"Why did you have to force Frederica to battle using the authority of the Operations Command?","TWN":"為何你不惜動用司令部的權限，也要將弗蕾德莉卡送上戰場呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"이유는 간단해. 그렇게 해서라도 내가 널 독차지하고 싶었으니까.","JPN":"理由は簡単だ。そうしてでもアタシはあんたを独り占めしたかったから。","ENG":"The reason is simple. I wanted you for myself.","TWN":"答案很簡單，因為我不惜這麼做也要得到你！"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"TWN":"　"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그래서, 이제 어쩔 셈이야?","JPN":"それで、これからどうするつもりだ？","ENG":"So, what are you going to do now?","TWN":"那你現在打算怎麼做？"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"우주로 떠나야지.","JPN":"宇宙に旅立つ。","ENG":"I’m leaving for outer space.","TWN":"當然是去宇宙囉。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"실종된 플라잉몬테규 호를 구하러.","JPN":"失踪したフライング・モンタギュー号を救うために。","ENG":"To save the lost Flying Montague.","TWN":"去拯救失蹤的普拉因蒙太古號！"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신이… 프레데리카를 구하겠다고?","JPN":"君が……フレデリカを救う？","ENG":"You’re saying you’re... going to save Frederica?","TWN":"你…要去救弗蕾德莉卡？"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그녀를 미워하고 있는 게 아니었어?","JPN":"彼女を恨んでいたんじゃないのか？","ENG":"But don’t you hate her?","TWN":"你不是討厭她嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"프레데리카는 아카데미 시절, 내가 유일하게 인정한 라이벌이었지.","JPN":"フレデリカはアカデミー時代、アタシが唯一認めたライバルだった。","ENG":"Frederica was my only rival when we were at the academy.","TWN":"弗蕾德莉卡是我在學院時期，唯一認可的對手。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그녀가 무릎 꿇는 건 내 앞이어야만 해. 적들의 앞이 아니라.","JPN":"彼女が跪くのは敵ではなくて、アタシであるべきなんだ。","ENG":"She should only kneel in front of me, not in front of the enemies.","TWN":"她不能向敵人屈膝，只能向我屈膝！"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"고작 그런 이유로 마음을 바꿨다고?","JPN":"そんな理由で心を変えたのか？","ENG":"That’s what made you change your mind?","TWN":"你只是因為這樣就改變心意？"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그리고 로미오, 내가 사랑하는 당신이 그녀의 생환을 원하고 있으니까.","JPN":"それにロミオ、アタシの愛するあんたが彼女の生還を望んでるから。","ENG":"And Romeo, my love, it’s you who want her back alive.","TWN":"另外一個原因就是你，羅密歐，因為我愛的你希望她能夠生還。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"정말이지… 역시 당신이란 사람답군.","JPN":"まったく……やはり君らしいな。","ENG":"I would say... You are so you.","TWN":"果然…很有你的作風。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정말 감동적이네요. 유마가 저런 긴 대사를 읊을 수 있게 되다니.","JPN":"とても感動的ですね。ユマがあんなに長いセリフを言えるようになるとは。","ENG":"This is so touching. I never thought Yuma would be able to memorize long lines like that.","TWN":"真是太感人，那麼長的台詞，游馬竟然說得出來。"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그야 저 감독이 파벨라 몫의 대사를 전부 판넬에 적어서 보여주고 있으니까.","JPN":"それは、あの監督がファヴェーラのセリフを全部カンペに書いて見せてあげてるからのう。","ENG":"It’s because the director’s showing all of Fabella’s lines on a panel.","TWN":"那是因為導演把帕貝拉的台詞都寫在大字報上吧！"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"현장에서도 느끼는 거지만, 정말이지 훌륭한 각본이군요.","JPN":"現場でも思ってたのですが、まったく素晴らしい脚本です。","ENG":"I can really feel that it’s a perfect script.","TWN":"光是在現場就很有感覺，這真是個很棒的劇本呢！"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"역시 명감독이라 불릴 만합니다.","JPN":"さすがは名監督。","ENG":"No wonder he’s a great director.","TWN":"確實有資格被稱為名導演。"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래, 그리고 내일이 되면, 이젠 나도 명감독의 반열에 오르게 되겠지.","JPN":"ああ、そして明日になれば、妾も名監督になるであろう。","ENG":"Yes, and when tomorrow comes, I’ll also be one of the greatest directors.","TWN":"沒錯，明天一到，我也會加入名導演的行列囉！"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"네? 하지만 주인님께선 오늘 아무것도…","JPN":"はい？　しかし、ご主人様は今日何も……","ENG":"What? But Mistress, you didn’t do anything today...","TWN":"嗯？可是主人今天好像什麼也…"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…음?","JPN":"……うむ？","ENG":"...Hmm?","TWN":"…嗯？"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"지금 저 판넬에 대체 뭐라고 적혀 있는 거죠?","JPN":"あのカンペになんて書いてあるのですか？","ENG":"What the hell is written on that panel?","TWN":"現在大字報上面是寫什麼？"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"로미오와 파벨라가 키스를 한다는구나.","JPN":"ロミオとファヴェーラがキスをするそうじゃのう。","ENG":"It says that Romeo and Fabella are going to kiss.","TWN":"羅密歐和帕貝拉接吻。"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"저 노을의 폭력적인 붉은 빛깔을 볼 때마다 당신이 떠오를 거야, 파벨라.","JPN":"あの夕暮れの暴力的な赤い色を見るたびに君のことを思い出すだろう、ファヴェーラ。","ENG":"The violent red color of the sunset will forever remind me of you, Fabella.","TWN":"帕貝拉，每次看到那火紅的彩霞都會令我想起你。"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신의 투지와 물불 가리지 않는 광기…","JPN":"君の闘志と猛烈な狂気……","ENG":"Your fighting spirit and madness...","TWN":"想起你的鬥志，想起你奮不顧身的瘋狂…"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그리고 그 새빨간 입술도.","JPN":"そして、その真っ赤な唇も。","ENG":"And those red lips.","TWN":"還有你的紅唇。"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"로미오…","JPN":"ロミオ……","ENG":"Romeo...","TWN":"羅密歐…"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"파벨라…","JPN":"ファヴェーラ……","ENG":"Fabella...","TWN":"帕貝拉…"},"stage":{"bg":"FALL_PARK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…피해!","JPN":"……危ない！","ENG":"...Watch out!","TWN":"…閃開！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…힉?! 궈, 권총…?","JPN":"……ひいっ！？　ぴ、ピストル……？","ENG":"...Shriek?! A p-pistol...?","TWN":"…呃？！是…槍…？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런. 잘도 피하셨군요.","JPN":"おっと。よくよけられましたね。","ENG":"Oh dear. You avoided the bullet.","TWN":"可惡，閃得很快嘛！"},"stage":{"bg":"FALL_PARK","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 다음 기회는 없습니다, 파벨라.","JPN":"ですが、次はありませんよ、ファヴェーラ。","ENG":"But there’s no next time, Fabella.","TWN":"下次可沒這麼好運，帕貝拉！"},"stage":{"bg":"FALL_PARK","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"이게 뭐하는 짓이야?","JPN":"何してやがる？","ENG":"What are you doing?","TWN":"你幹嘛啦？"},"stage":{"bg":"FALL_PARK","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"파벨라. 난 당신이 그 무엇에도 간섭 받지 않고 자유롭길 원한답니다.","JPN":"ファヴェーラ。私はあなたが何のしがらみにも囚われず、自由であってほしいです。","ENG":"Fabella. I always wish you are free without interference.","TWN":"帕貝拉，我向來不會干涉你，讓你想做什麼就做什麼。"},"stage":{"bg":"FALL_PARK","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 이것만큼은 용납할 수 없군요! 오늘 처음 만난 남자에게 입술을 내어 주려 하다니!","JPN":"ですが、これだけは許せません！　今日初めて会った男と口づけするとは！","ENG":"But this is unacceptable! You try to lock your lips with a man you literally met today?","TWN":"但唯有這個我無法接受！怎麼可以把嘴唇送給今天才見面的男生！"},"stage":{"bg":"FALL_PARK","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭔 소릴 하는 거야? 이건 내가 결투에서 얻어낸 돈줄이라고!","JPN":"何言ってるんだ？　これはアタシが決闘して手に入れた金づるなんだよ！","ENG":"What are you talking about? I earned this job by myself!","TWN":"你在說什麼？這是我在決鬥中得到的搖錢樹欸！"},"stage":{"bg":"FALL_PARK","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"아무리 오빠라도 이건 순순히 양보 못 해!","JPN":"いくら兄さんでもこれは素直に譲れない！","ENG":"I’m not letting you take it away from me!","TWN":"就算你是我哥，我也不會輕易讓步的！"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후후, 우리 동생이 오라버니에게 반항하는 건 오랜만이구나.","JPN":"フフフ、妹が兄に反抗するのは久しぶりだな。","ENG":"Ha ha, it’s been a long time since you rebelled against me like this.","TWN":"呵呵呵，妹妹現在是要久違地反抗哥哥嗎！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐래? 한 번도 이긴 적 없으면서 언제부터 자기가 위였다고!","JPN":"はあ？　一度も勝ったことないくせに、自分が上だって思うなよ！","ENG":"What are you talking about? You’ve never won.","TWN":"你說什麼？你根本連一次都沒贏過，少一副高高在上的樣子！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"돈이라면 내가 얼마든지 마련할 수 있단다.","JPN":"お金なら私がいくらでも稼げる。","ENG":"If it’s money that you need, I can get it for you.","TWN":"你要錢的話，多少我都可以給你弄來！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"시끄러! 매일 탐정일만 하면서 돈도 못 벌잖아!","JPN":"うるさい！　毎日探偵の仕事をしてるくせに、金稼げてないじゃないか！","ENG":"Shut up! All you do is work as a detective and you can’t even earn money!","TWN":"騙人！每天光是做偵探的事，根本沒辦法賺錢！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"고작 돈 때문에 널 팔아 넘길 순 없어!","JPN":"お金のために妹を売り渡すことはできない！","ENG":"I can’t sell you out just for the money!","TWN":"我是不會因為錢就出賣妹妹的！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐래! 당장 어제만 해도 돈이 없어서 스테이크를 찾던 주인님이 돈까스만 먹었다고!","JPN":"何言ってるんだよ！　昨日だって金がなくてステーキを食べたがってた主様がトンカツを食べてたじゃないか！","ENG":"Hah, what? Our Mistress had to have pork chops instead of steak yesterday because we didn’t have enough money!","TWN":"你說什麼？昨天主人原本想吃牛排的，結果因為沒有錢只能吃滷肉飯！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"연인을 위해 희생할 각오조차 되어 있지 않은 남자에게 널 넘겨줄 순 없단다!","JPN":"恋人のために犠牲になる覚悟すらできていない男に、我が妹は渡せない！","ENG":"I can’t give you away to a man that’s not even ready to sacrifice himself for his lover!","TWN":"我不能把你交給一個沒有決心替另一半擋子彈的男人！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"날 방해하겠다면 아무리 오빠라도 안 봐줘!","JPN":"アタシを邪魔するつもりなら、いくら兄さんでも手加減しない！","ENG":"If you’re trying to bother me, I’m not going to cut you a break!","TWN":"你敢妨礙我的話，就算是哥哥我也不會留情面的！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇다면 결투다!","JPN":"それなら決闘だ！","ENG":"Then it’s a duel!","TWN":"那來決鬥吧！"},"stage":{"bg":"FALLEN_01","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};